 // BitArrays in patterns, guards, and expressions have a very similar structure
 // but need specific types. These are helpers for that. There is probably a
 // rustier way to do this :)
+fn clause_guard_to_pattern(guard: UntypedClauseGuard) -> UntypedPattern {
+    match guard {
+        ClauseGuard::Constant(constant) => match constant {
+            Constant::Int {
+                location,
+                value,
+                int_value,
+            } => Pattern::Int {
+                location,
+                value,
+                int_value,
+            },
+            _ => Pattern::Invalid {
+                location: constant.location(),
+                type_: (),
+            },
+        },
+
+        ClauseGuard::Var { name, location, .. } => Pattern::VarUsage {
+            location,
+            name,
+            constructor: None,
+            type_: (),
+        },
+
+        ClauseGuard::AddInt {
+            location,
+            left: _,
+            right: _,
+        } => Pattern::Assign {
