            if let Some((_, Token::LtGt, _)) = self.tok0.as_ref() {
                return concat_pattern_variable_left_hand_side_error(start, end);
            }

            Pattern::Discard {
                location: SrcSpan { start, end },
                name,
                type_: (),
            }
        }

