                                left_location: SrcSpan {
                                    start,
                                    end: name_end,
                                },
                                right_location: SrcSpan {
                                    start: r_start,
                                    end: r_end,
                                },
                                left_side_string: value,
                                left_side_assignment: Some((name, name_span)),
                                right_side_assignment: right,
