    match guard {
        ClauseGuard::Constant(constant) => match constant {
            Constant::Int {
                location,
                value,
                int_value,
            } => Pattern::Int {
                location,
                value,
                int_value,
            },
            _ => Pattern::Invalid {
                location: constant.location(),
                type_: (),
            },
        },

        ClauseGuard::Var { name, location, .. } => Pattern::VarUsage {
            location,
            name,
            constructor: None,
            type_: (),
        },

        ClauseGuard::AddInt {
            location,
            left,
            right,
        } => Pattern::Assign {
            // Reuse the assignment pattern as an AST container for operators,
            // as patterns don't have a dedicated binary operator node.
            name: CAPTURE_VARIABLE.into(),
            location,
            pattern: Box::new(Pattern::Invalid {
                location,
                type_: (),
            }),
        },

        ClauseGuard::SubInt {
            location,
            left: _,
            right: _,
        }
        | ClauseGuard::MultInt {
            location,
            left: _,
            right: _,
        }
        | ClauseGuard::DivInt {
            location,
            left: _,
            right: _,
        }
        | ClauseGuard::RemainderInt {
            location,
            left: _,
            right: _,
        }
        | ClauseGuard::NegateInt { location, .. } => Pattern::Invalid { location, type_: () },

        // Other guard forms aren't valid for size expressions.
        other => Pattern::Invalid {
            location: other.location(),
            type_: (),
        },
    }
}

